import{_ as t,o as a,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"139. Study Leave","description":"","frontmatter":{"title":"139. Study Leave","eba":"Mental Health Services 2024-2028","topics":["leave","study-leave","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/education-pd/139-study-leave.md","filePath":"ebas/mental-health/health-professionals/education-pd/139-study-leave.md"}'),l={name:"ebas/mental-health/health-professionals/education-pd/139-study-leave.md"};function r(n,e,i,p,d,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_139-study-leave" tabindex="-1">139. Study Leave <a class="header-anchor" href="#_139-study-leave" aria-label="Permalink to &quot;139. Study Leave&quot;">​</a></h1><p><strong>139.1</strong> Paid study leave will be available to all Employees employed in full-time and part- time employment at the Employer&#39;s discretion.</p><p><strong>139.2</strong> Paid study leave may be taken as agreed between the Employer and an Employee by, for example, 4 hours per week, 8 hours per fortnight or blocks of 38 hours at a residential school.</p><p><strong>139.3</strong> Employees employed in part-time employment will be entitled to paid study leave on a pro-rata basis</p><p><strong>139.4</strong> An Employee wishing to take study leave in accordance with this clause must apply in writing to the Employer as early as possible prior to the proposed leave date. The Employee&#39;s request should include:</p><p><strong>(a)</strong> details of the course and institution in which the Employee is enrolled or proposes to enrol; and</p><p><strong>(b)</strong> details of the relevance of the course to the Employee&#39;s profession.</p><p><strong>139.5</strong> The Employer will notify the Employee of whether their request for study leave has been approved within 7 days of the application being made.</p><p><strong>139.6</strong> Leave pursuant to this clause does not accumulate from year to year.</p><p>Plain language terms: exam leave, education leave.</p>',10)])])}const y=t(l,[["render",r]]);export{m as __pageData,y as default};
